package leetcode.all;

import utils.TestUtil;

public class LongestSubstringWithAtLeastKRepeatingCharacters {
    private boolean isStable(int[] freq, int k) {
        for (int f: freq) {
            if (f > 0 && f < k) {
                return false;
            }
        }

        return true;
    }
    public int longestSubstring(String s, int k) {
        int n = s.length();
        if (k < 2) return n;

        int maxUnique = 0, longestStable = 0;
        int[] freq = new int[26];
        
        for (int i = 0; i < n; i++) {
            if (freq[s.charAt(i) - 'a'] == 0) {
                maxUnique++;
            }
            freq[s.charAt(i) - 'a']++;
        }

        for (int unique = 1; unique <= maxUnique; unique++) {
            int[] fCount = new int[26];

            int start = 0, end = 0, currUnique = 0;

            while (end < n && start < n) {
                
                if (currUnique <= unique) {
                    if (fCount[s.charAt(end) - 'a'] == 0) {
                        currUnique++;
                    }
                    fCount[s.charAt(end) - 'a']++;

                    if (this.isStable(fCount, k)) {
                        longestStable = Math.max(end - start + 1, longestStable);
                    }
                    end++;
                } else {
                    fCount[s.charAt(start) - 'a']--;
                    if (fCount[s.charAt(start++) - 'a'] == 0) {
                        currUnique--;
                    }
                }
            }
        }

        return longestStable;
    }

    public static void main(String[] args) {
        LongestSubstringWithAtLeastKRepeatingCharacters solution = new LongestSubstringWithAtLeastKRepeatingCharacters();

        TestUtil.run("TEST CASE: #1", 3, solution.longestSubstring("aaabb", 3));
        TestUtil.run("TEST CASE: #2", 5, solution.longestSubstring("ababbc", 2));
        TestUtil.run("TEST CASE: #3", 301, solution.longestSubstring("", 301));

        
    }
}
